sql:
SELECT location, COUNT(hotel_id) AS number_of_hotels
FROM hotels
GROUP BY location;

SELECT number_of_rooms AS total_rooms
FROM hotels
WHERE hotel_id = 1;

SELECT hotel_name
FROM hotels
WHERE location = 'New York, USA' AND rating >= 4.5;

external_knowledge:
- 'typical occupancy rate' refers to the average occupancy rate over a given period;
- 'revenue per available room' (RevPAR) is a measure of a hotel's revenue efficiency;
- 'particular hotel' refers to the hotel with `hotel_id = 1`;
- 'past year' refers to the year 2023, which is the date range used in the SQL query.

sql:
SELECT hotel_id, COUNT(reservation_id) AS number_of_reservations
FROM reservations
GROUP BY hotel_id;

SELECT number_of_rooms AS total_rooms
FROM hotels
WHERE hotel_id = 1;

SELECT hotel_id
FROM analytics
WHERE occupancy_rate = (
    SELECT MAX(occupancy_rate)
    FROM analytics
);

SELECT hotel_id, AVG(revenue) AS average_revenue_per_hotel
FROM analytics
GROUP BY hotel_id;

SELECT SUM(a.revenue) AS total_revenue
FROM analytics a
WHERE a.hotel_id = 1 AND a.report_date LIKE '2023-07-%';
